<?php
require_once __DIR__.'/functions.php';require_admin();$posts=db()->query("SELECT p.id,p.titulo,p.slug,p.contenido,p.imagen,p.author_name,p.status,p.fecha,m.email,m.avatar,m.profile_slug,m.profile_public FROM posts p LEFT JOIN members m ON m.id=p.member_author_id WHERE p.post_type='community' ORDER BY FIELD(p.status,'pending','rejected','published'),p.fecha DESC")->fetchAll();render_header('Publicaciones de la comunidad',['robots'=>'noindex,nofollow']);?><section class="panel"><div class="moderation-title"><div><h1>Publicaciones de la comunidad</h1><p class="muted">Revisa los temas enviados por lectores.</p></div><span class="count-badge"><?=count($posts)?></span></div><?php foreach($posts as $post):?><article class="moderation"><div class="moderation-user"><?php $profileUrl=public_profile_url($post);if($profileUrl):?><a class="author-profile-link" href="<?=e($profileUrl)?>"><?php endif;?><?php if($post['avatar']):?><img class="avatar member-admin-avatar" src="/uploads/<?=e($post['avatar'])?>" alt="Avatar de <?=e($post['author_name'])?>"><?php else:?><span class="avatar member-admin-avatar avatar-fallback"><?=e(mb_strtoupper(mb_substr($post['author_name'],0,1)))?></span><?php endif;?><span><strong><?=e($post['author_name'])?></strong><small><?=e($post['email'])?> · <?=e(format_date($post['fecha'],true))?></small></span><?php if($profileUrl):?></a><?php endif;?></div><h2><?=e($post['titulo'])?></h2><p><?=e(mb_strimwidth(strip_tags($post['contenido']),0,260,'…'))?></p><div class="actions"><a class="button secondary" href="/<?=e($post['slug'])?>">Vista previa</a><form method="post" action="/community-action.php"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><input type="hidden" name="post_id" value="<?=(int)$post['id']?>"><button class="button" name="action" value="approve">Aprobar</button><button class="button warn" name="action" value="reject">Rechazar</button><button class="button danger-bg" name="action" value="delete">Eliminar</button></form></div></article><?php endforeach;?><?php if(!$posts):?><p class="empty">No hay publicaciones comunitarias.</p><?php endif;?></section><?php render_footer();
